using TendexAI.Domain.Common;
using TendexAI.Domain.Enums;

namespace TendexAI.Domain.Entities.Evaluation;

/// <summary>
/// Represents an award recommendation for a competition.
/// Auto-generated by the system based on combined technical and financial results.
/// Per PRD Section 11.
/// </summary>
public sealed class AwardRecommendation : BaseEntity<Guid>
{
    private readonly List<AwardRanking> _rankings = [];

    private AwardRecommendation() { }

    public static AwardRecommendation Create(
        Guid competitionId, Guid tenantId, Guid financialEvaluationId,
        Guid recommendedOfferId, string recommendedSupplierName,
        decimal technicalScore, decimal financialScore, decimal combinedScore,
        decimal totalOfferAmount, string justification, string createdBy)
    {
        return new AwardRecommendation
        {
            Id = Guid.NewGuid(),
            CompetitionId = competitionId,
            TenantId = tenantId,
            FinancialEvaluationId = financialEvaluationId,
            RecommendedOfferId = recommendedOfferId,
            RecommendedSupplierName = recommendedSupplierName,
            TechnicalScore = technicalScore,
            FinancialScore = financialScore,
            CombinedScore = combinedScore,
            TotalOfferAmount = totalOfferAmount,
            Justification = justification,
            Status = AwardStatus.Draft,
            CreatedAt = DateTime.UtcNow,
            CreatedBy = createdBy
        };
    }

    public Guid CompetitionId { get; private set; }
    public Guid TenantId { get; private set; }
    public Guid FinancialEvaluationId { get; private set; }
    public Guid RecommendedOfferId { get; private set; }
    public string RecommendedSupplierName { get; private set; } = default!;
    public decimal TechnicalScore { get; private set; }
    public decimal FinancialScore { get; private set; }
    public decimal CombinedScore { get; private set; }
    public decimal TotalOfferAmount { get; private set; }
    public string Justification { get; private set; } = default!;
    public AwardStatus Status { get; private set; }
    public DateTime? ApprovedAt { get; private set; }
    public string? ApprovedBy { get; private set; }
    public string? RejectionReason { get; private set; }

    public IReadOnlyCollection<AwardRanking> Rankings => _rankings.AsReadOnly();

    public Result AddRanking(AwardRanking ranking)
    {
        var exists = _rankings.Any(r => r.SupplierOfferId == ranking.SupplierOfferId);
        if (exists) return Result.Failure("A ranking already exists for this offer.");
        _rankings.Add(ranking);
        return Result.Success();
    }

    public Result SubmitForApproval(string submittedBy)
    {
        if (Status != AwardStatus.Draft)
            return Result.Failure("Award can only be submitted from Draft status.");
        Status = AwardStatus.PendingApproval;
        LastModifiedAt = DateTime.UtcNow;
        LastModifiedBy = submittedBy;
        return Result.Success();
    }

    public Result Approve(string approvedBy)
    {
        if (Status != AwardStatus.PendingApproval)
            return Result.Failure("Award can only be approved from PendingApproval status.");
        Status = AwardStatus.Approved;
        ApprovedAt = DateTime.UtcNow;
        ApprovedBy = approvedBy;
        LastModifiedAt = DateTime.UtcNow;
        LastModifiedBy = approvedBy;
        return Result.Success();
    }

    public Result Reject(string rejectedBy, string reason)
    {
        if (Status != AwardStatus.PendingApproval)
            return Result.Failure("Award can only be rejected from PendingApproval status.");
        if (string.IsNullOrWhiteSpace(reason))
            return Result.Failure("A rejection reason is required.");
        Status = AwardStatus.Rejected;
        RejectionReason = reason;
        LastModifiedAt = DateTime.UtcNow;
        LastModifiedBy = rejectedBy;
        return Result.Success();
    }
}
